const accentAt = (i) => [T.accent, T.accent2, "#6b9b8b", "#ff8c42", "#ff6b6b"][i % 5];

const gemScore = (reviews) => {
  if (!reviews) return 5;
  if (reviews < 100) return 10;
  if (reviews < 500) return 8;
  if (reviews < 2000) return 6;
  if (reviews < 5000) return 4;
  return 2;
};

